// Input validation for required fields
const body = $json.body || $json;

const requiredFields = ['payment_status', 'customer_email', 'customer_name'];
const missing = requiredFields.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error(`Validation Error: Missing required fields: ${missing.join(', ')}`);
}

// Validate email format
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.customer_email)) {
  throw new Error(`Validation Error: Invalid email format: ${body.customer_email}`);
}

// Sanitize customer_name (strip HTML)
body.customer_name = (body.customer_name || '').replace(/<[^>]*>/g, '').trim();

return [{ json: { body } }];

// Rate limit: 1 delivery per email per 24 hours
const staticData = $getWorkflowStaticData('global');
if (!staticData.deliveryRateLimit) {
  staticData.deliveryRateLimit = {};
}

const email = $json.body.customer_email.toLowerCase();
const now = Date.now();
const twentyFourHours = 24 * 60 * 60 * 1000;

// Cleanup old entries (older than 48h)
for (const [key, ts] of Object.entries(staticData.deliveryRateLimit)) {
  if (now - ts > twentyFourHours * 2) {
    delete staticData.deliveryRateLimit[key];
  }
}

const lastDelivery = staticData.deliveryRateLimit[email];
if (lastDelivery && (now - lastDelivery) < twentyFourHours) {
  const hoursRemaining = Math.ceil((twentyFourHours - (now - lastDelivery)) / 3600000);
  throw new Error(`Rate limit: Delivery already sent to ${email}. Try again in ${hoursRemaining}h.`);
}

// Record this delivery
staticData.deliveryRateLimit[email] = now;

return $input.all();

// Confirmation: delivery was successful
const body = $('Validate Input').first().json.body;
const logEntry = {
  status: 'success',
  customer_email: body.customer_email,
  customer_name: body.customer_name,
  amount: body.amount || 'N/A',
  delivered_at: new Date().toISOString()
};
console.log('Toolkit Delivery Success:', JSON.stringify(logEntry));
return [{ json: { ...logEntry, body } }];

// Error notification handler
const error = $input.first().json;
const logEntry = {
  workflow: 'AI Toolkit Delivery',
  error: error.message || 'Unknown error',
  node: error.node?.name || 'unknown',
  timestamp: new Date().toISOString()
};
console.error('Toolkit Delivery Error:', JSON.stringify(logEntry));
return [{ json: logEntry }];
